+/// GraphML attribute type (follows Java type naming per GraphML spec).
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord)]
+enum GraphMLType {
+    Boolean,
+    Int,
+    Long,
+    Float,
+    Double,
+    String,
+}
+
+impl GraphMLType {
+    fn as_str(self) -> &'static str {
+        match self {
+            Self::Boolean => "boolean",
+            Self::Int => "int",
+            Self::Long => "long",
+            Self::Float => "float",
+            Self::Double => "double",
+            Self::String => "string",
+        }
+    }
+
+    /// Infer type from a `CgseValue`.
+    ///
+    /// Maps directly from the value's *variant* (which reflects the Python
+    /// source type) rather than parsing string contents.  This matches NX
+    /// behavior where `type(value)` determines the GraphML attr.type:
+    ///   Python int   → "int"
+    ///   Python float → "double"  (even 3.0 — NX uses `type(3.0)` = float)
+    ///   Python bool  → "boolean"
+    ///   Python str   → "string"  (even "42" or "true")
+    fn from_cgse_value(val: &CgseValue) -> Self {
+        match val {
+            CgseValue::Int(_) => Self::Int,
+            CgseValue::Float(_) => Self::Double,
+            CgseValue::Bool(_) => Self::Boolean,
+            CgseValue::String(_) => Self::String,
+        }
+    }
+
+    /// Generalize across multiple types: NX rules
+    fn generalize(types: &HashSet<Self>) -> Self {
+        if types.contains(&Self::String) || types.len() > 2 {
+            return Self::String;
+        }
+        if types.contains(&Self::Double) || types.contains(&Self::Float) {
+            if types
+                .iter()
+                .all(|t| matches!(t, Self::Double | Self::Float | Self::Int | Self::Long))
+            {
+                return Self::Double;
+            }
+            return Self::String;
+        }
+        if types.contains(&Self::Long) && types.contains(&Self::Int) {
+            return Self::Long;
+        }
+        if types.len() == 1 {
+            return *types.iter().next().unwrap();
+        }
+        Self::String
+    }
+}
