+/// Indentation/whitespace helpers for GraphML emission.
+struct GraphMLIndent {
+    nl: &'static str, // "\n" when prettyprint, "" otherwise
+    i1: &'static str, // "  " (2-space indent level 1)
+    i2: &'static str, // "    " (level 2)
+    i3: &'static str, // "      " (level 3)
+}
+
+impl GraphMLIndent {
+    fn new(prettyprint: bool) -> Self {
+        if prettyprint {
+            Self {
+                nl: "\n",
+                i1: "  ",
+                i2: "    ",
+                i3: "      ",
+            }
+        } else {
+            Self {
+                nl: "",
+                i1: "",
+                i2: "",
+                i3: "",
+            }
+        }
+    }
+}
+
+/// Emit the GraphML XML header (declaration + opening graphml tag).
+fn graphml_emit_header(xml: &mut String, ind: &GraphMLIndent) {
+    xml.push_str("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
+    xml.push_str(ind.nl);
+    xml.push_str("<graphml xmlns=\"http://graphml.graphdrawing.org/xmlns\"");
+    xml.push_str(" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"");
+    xml.push_str(" xsi:schemaLocation=\"http://graphml.graphdrawing.org/xmlns");
+    xml.push_str(" http://graphml.graphdrawing.org/xmlns/1.0/graphml.xsd\">");
+    xml.push_str(ind.nl);
+}
